#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<vector<int>> zigzagLevelOrder(TreeNode* root) {
        if (!root) return {};
        vector<vector<int>> result;
        queue<TreeNode*> q;
        q.push(root);
        bool leftToRight = true;
        while (!q.empty()) {
            int levelSize = q.size();
            vector<int> levelValues;
            for (int i = 0; i < levelSize; i++) {
                TreeNode* node = q.front(); q.pop();
                if (leftToRight) levelValues.push_back(node->val);
                else levelValues.insert(levelValues.begin(), node->val);
                if (node->left) q.push(node->left);
                if (node->right) q.push(node->right);
            }
            result.push_back(levelValues);
            leftToRight = !leftToRight;
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    int rootVal;
    if (!(cin >> rootVal)) return 0;
    TreeNode* root = new TreeNode(rootVal);
    vector<TreeNode*> nodes = {root};
    for (int i = 0; i < n - 1; i++) {
        int nodeVal, leftVal, rightVal;
        if (!(cin >> nodeVal >> leftVal >> rightVal)) return 0;
        TreeNode* node = nodes[i];
        if (leftVal != -1) {
            node->left = new TreeNode(leftVal);
            nodes.push_back(node->left);
        }
        if (rightVal != -1) {
            node->right = new TreeNode(rightVal);
            nodes.push_back(node->right);
        }
    }
    Solution sol;
    vector<vector<int>> ans = sol.zigzagLevelOrder(root);
    for (const auto& level : ans) {
        for (int val : level) cout << val << " ";
        cout << "\n";
    }
    return 0;
}
